                    if (rank >= 6) {hitSplitters[sourceTurn.properName].basic2[1].perHitMultiOverride = 0.40;}

                    let values = battleActions.getLevelBasedParam(battleData,skillRef,sourceTurn);
                    const scalar = "ATK";
