                        [EffectRES]: values2[3] + (rank >= 4 ? 0.50 : 0),
                        [DEFShredSkill]: rank >= 1 ? 0.15 : 0,
                        [ResistanceFirePEN]: rank >= 6 ? 0.20 : 0,
