                        allToughness: false,//Module α: Antilag Outburst, see hit start listener
                        toughnessCondition: null,//logicRef.skillFunctions.antilagToughnessAdjustment,
                        slot: skillRef.slot,
                        realDMGKeys,realPENKeys,realShredKeys,realVulnKeys,
