                        [WeaknessFire]: 1,
                        "source": characterName,
                        "sourceOwner": sourceTurn.properName,
                        "buffName": buffName,
                        "durationInTurn": 3,
                        "duration": 2,//her skill will never be applied outside her own turn, so we don't need to worry about the primary target's turn state duration increase
                        "AVApplied": 0,
