                let ATKObject = ATKObjects.evaFUAATKOBJECT;

                poke("TalentStart",battleData,{sourceTurn});

                const battleValues = sourceTurn.battleValues;
                battleValues.fuaTrackerValue -= 240;
                battleValues.fuaIsQueued = false;

